import React, { useState, useEffect, useRef } from "react";
import Sidebar from "../../components/Admin/Sidebar";
import TopBar from "../../components/Admin//TopBar";
import DataTable from "react-data-table-component";
import { Modal, Button } from "react-bootstrap";
import { useNavigate, Link } from "react-router-dom";
import { FaEye, FaEllipsisV, FaTrashAlt, FaGift, FaShareAlt, FaArrowLeft } from "react-icons/fa";

import SuccessAlert from "../../components/Admin/SuccessAlert";
import * as XLSX from "xlsx";
import { saveAs } from "file-saver";
import axios from "axios";
import { API_BASE_URL } from "../../config/config";

/* ── Action dropdown styles only ── */
const actionStyles = `
  .au-action-btn {
    width: 32px;
    height: 32px;
    border: 1.5px solid #e2e8f0;
    background: #fff;
    border-radius: 8px;
    display: grid;
    place-items: center;
    cursor: pointer;
    color: #64748b;
    transition: background .15s, border-color .15s, color .15s;
    padding: 0;
  }
  .au-action-btn:hover {
    background: #f1f5f9;
    border-color: #cbd5e1;
    color: #0f172a;
  }
  .au-dropdown {
    position: fixed;
    min-width: 195px;
    background: #fff;
    border: 1px solid #e8edf2;
    border-radius: 12px;
    box-shadow: 0 8px 30px rgba(0,0,0,.13), 0 2px 8px rgba(0,0,0,.06);
    padding: 6px;
    z-index: 99999;
    animation: auFadeIn .15s ease-out;
  }
  @keyframes auFadeIn {
    from { opacity: 0; transform: translateY(-6px) scale(.97); }
    to   { opacity: 1; transform: translateY(0) scale(1); }
  }
  .au-drop-item {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 9px 12px;
    border-radius: 8px;
    font-size: 0.84rem;
    font-weight: 500;
    color: #334155;
    cursor: pointer;
    text-decoration: none !important;
    border: none;
    background: transparent;
    width: 100%;
    font-family: inherit;
    transition: background .12s, color .12s;
    line-height: 1;
  }
  .au-drop-item:hover {
    background: #f1f5f9;
    color: #0f172a;
    text-decoration: none !important;
  }
  .au-drop-item.danger { color: #dc2626; }
  .au-drop-item.danger:hover { background: #fef2f2; color: #b91c1c; }
  .au-drop-item svg { font-size: 13px; flex-shrink: 0; }
  .au-drop-divider { height: 1px; background: #f1f5f9; margin: 5px 6px; }
`;

/* ── Portal-style dropdown — fixed position so never clipped by table overflow ── */
function ActionDropdown({ row, triggerRect, onClose, onDelete }) {
  const ref = useRef(null);

  useEffect(() => {
    const handler = (e) => {
      if (ref.current && !ref.current.contains(e.target)) onClose();
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, [onClose]);

  const top = triggerRect ? triggerRect.bottom + window.scrollY + 4 : 0;
  const right = triggerRect
    ? window.innerWidth - triggerRect.right - window.scrollX
    : 0;

  return (
    <div ref={ref} className="au-dropdown" style={{ top, right: Math.max(right, 8) }}>
      {row.discount_code && (
        <Link
          className="au-drop-item"
          target="_blank"
          to={`/admin/company/referralused/${row.discount_code}/${row.id}`}
          onClick={onClose}
        >
          <FaGift /> Referral Codes Used
        </Link>
      )}
      <Link
        className="au-drop-item"
        to={`/admin/users/company/${row.id}`}
        onClick={onClose}
      >
        <FaEye /> View All Companies
      </Link>
      <div className="au-drop-divider" />
      <button
        className="au-drop-item danger"
        onClick={() => { onDelete(row.id); onClose(); }}
      >
        <FaTrashAlt /> Delete
      </button>
    </div>
  );
}

function AdminUsers() {
  const navigate = useNavigate();
  const [isOpen, setIsOpen] = useState(false);
  const [show, setShow] = useState(false);
  const [successMessage, setsuccessMessage] = useState("");
  const toggleNavAdmin = () => {
    setIsOpen(!isOpen);
  };
  const apiUrl = API_BASE_URL + "api/admin/module/";
  const [records, setRecords] = useState([]);
  document.title = "All User - Admin";

  useEffect(() => {
    getallusers();
  }, []);

  const getallusers = async () => {
    let formData = { user_id: "" };
    try {
      const res = await axios.post(apiUrl + "getallusers", formData, {
        headers: {
          Accept: "application/json",
          "Content-Type": "application/json",
        },
      });
      var respo = res.data.results;
      setRecords(respo);
    } catch (err) {
      if (err.response) {
      } else if (err.request) {
        console.error("Request data:", err.request);
      } else {
        console.error("Error message:", err.message);
      }
    }
  };

  // ── Only these two state vars changed (added triggerRect) ──
  const [openDropdown, setOpenDropdown] = useState(null);
  const [triggerRect, setTriggerRect] = useState(null);

  const toggleDropdown = (id, rect) => {
    if (openDropdown === id) {
      setOpenDropdown(null);
    } else {
      setOpenDropdown(id);
      setTriggerRect(rect);
    }
  };

  const columns = [
    {
      name: "First Name",
      selector: (row) => row.first_name,
      sortable: true,
      className: "age",
    },
    {
      name: "Last Name",
      selector: (row) => row.last_name,
      sortable: true,
      className: "age",
    },
    {
      name: "Phone Number",
      selector: (row) => row.phone_number,
      sortable: true,
      className: "age",
    },
    {
      name: "Account Status",
      selector: (row) => row.status,
      sortable: true,
      className: "age",
      cell: (row) => (
        <span style={{
          color: row.status?.toLowerCase() === 'active' ? '#10b981' : '#ef4444',
          fontWeight: 500
        }}>
          {row.status?.toLowerCase() === 'active' ? 'Active' : 'Inactive'}
        </span>
      ),
    },
    {
      name: "Total Company",
      selector: (row) => row.total_company,
      sortable: true,
      className: "age",
    },
    {
      name: "Actions",
      cell: (row) => (
        <div style={{ position: "relative" }}>
          {/* ── New action button ── */}
          <button
            className="au-action-btn"
            onClick={(e) => {
              e.stopPropagation();
              const rect = e.currentTarget.getBoundingClientRect();
              toggleDropdown(row.id, rect);
            }}
          >
            <FaEllipsisV size={12} />
          </button>

          {/* ── New dropdown (fixed-position, never clipped) ── */}
          {openDropdown === row.id && (
            <ActionDropdown
              row={row}
              triggerRect={triggerRect}
              onClose={() => setOpenDropdown(null)}
              onDelete={handleDelete}
            />
          )}
        </div>
      ),
      ignoreRowClick: true,
      allowOverflow: true,
      button: true,
    },
  ];

  const [deleteId, setdeleteId] = useState("");
  const handleDelete = (id) => {
    setdeleteId(id);
    setShow(true);
  };
  const handleClose = () => {
    setShow(false);
  };
  const handleConfirmDelete = async () => {
    let formData = { id: deleteId };
    try {
      const res = await axios.post(apiUrl + "deleteUsers", formData, {
        headers: {
          Accept: "application/json",
          "Content-Type": "application/json",
        },
      });
      var respo = res.data;
      setShow(false);
      getallusers();
      setsuccessMessage(respo.message);
      setTimeout(() => {
        setsuccessMessage("");
      }, 1200);
    } catch (err) {
      if (err.response) {
      } else if (err.request) {
        console.error("Request data:", err.request);
      } else {
        console.error("Error message:", err.message);
      }
    }
  };

  const [searchQuery, setSearchQuery] = useState("");

  const filteredRecords = records.filter((record) => {
    const search = searchQuery.toLowerCase();
    return (
      (record.first_name?.toLowerCase() || "").includes(search) ||
      (record.last_name?.toLowerCase() || "").includes(search) ||
      (record.phone_number?.toLowerCase() || "").includes(search) ||
      (record.status?.toLowerCase() || "").includes(search) ||
      String(record.total_company || "").toLowerCase().includes(search)
    );
  });

  const handleViewsubscriptionList = (id) => { };

  const handleexportdata = () => {
    if (!records.length) return;
    const exportData = records.map((row) => ({
      "Company Name": row.company_name,
      "Phone Number": `${row.phone}`,
      "Number Of Employee": row.employee_number,
      "Company Website": row.company_website,
      "Total Signatory": row.total_signatories,
    }));
    const worksheet = XLSX.utils.json_to_sheet(exportData);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Companies");
    const excelBuffer = XLSX.write(workbook, { bookType: "xlsx", type: "array" });
    const data = new Blob([excelBuffer], {
      type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet;charset=UTF-8",
    });
    saveAs(data, "companies_export.xlsx");
  };

  const customStyles = {
    table: {
      style: {
        overflow: "visible !important",
        minWidth: "100%",
        boxShadow: "0px 3px 12px rgb(0 0 0 / 16%)",
        borderRadius: "12px",
      },
    },
    headCells: {
      style: {
        backgroundColor: "#efefef !important",
        fontWeight: "600",
        fontSize: "0.9rem",
        color: "#000 !important",
        whiteSpace: "nowrap",
      },
    },
    cells: {
      style: {
        whiteSpace: "nowrap",
        textOverflow: "ellipsis",
        backgroundColor: "#fff !important",
      },
    },
    rows: {
      style: {
        fontSize: "0.8rem",
        fontWeight: "500",
        "&:hover": {
          backgroundColor: "#e8f0fe",
        },
      },
      stripedStyle: {
        backgroundColor: "#f4f6f8",
      },
    },
    pagination: {
      style: {
        backgroundColor: "#fafafa",
        padding: "12px 16px",
      },
    },
  };

  return (
    <>
      <style>{actionStyles}</style>

      <div>
        <div className="d-flex align-items-start gap-0">
          <Sidebar />
          <div className="d-flex flex-column gap-0 w-100 dashboard_padding">
            <TopBar />
            <section className="dashboard_adminh">
              <div className="container-xl">
                <div className="row gy-4">
                  <div className="col-12">
                    <div className="card p-3">
                      {successMessage && (
                        <SuccessAlert
                          message={successMessage}
                          onClose={() => setsuccessMessage("")}
                        />
                      )}
                      <div className="d-flex justify-content-between gap-2 flex-wrap mb-2">
                        <div className="d-flex align-items-center gap-3">
                          <Link to="/admin/users" className="btn btn-secondary">
                            <FaArrowLeft /> Back
                          </Link>
                          <div>
                            <h5 className="mb-1">Users</h5>
                          </div>
                        </div>
                        <h5 className="mb-4">User All Companies</h5>
                      </div>

                      <div className="d-flex justify-content-between flex-wrap gap-3 pb-3 align-items-center">
                        <div className="d-flex justify-content-end flex-wrap align-items-end">
                          <div class="search-bar">
                            <input
                              type="text"
                              placeholder="Search..."
                              value={searchQuery}
                              onChange={(e) => setSearchQuery(e.target.value)}
                            />
                            <span class="search-icon">
                              <svg
                                xmlns="http://www.w3.org/2000/svg"
                                fill="none"
                                viewBox="0 0 24 24"
                                stroke="currentColor"
                              >
                                <path
                                  stroke-linecap="round"
                                  stroke-linejoin="round"
                                  stroke-width="2"
                                  d="M21 21l-4.35-4.35M17 11a6 6 0 11-12 0 6 6 0 0112 0z"
                                />
                              </svg>
                            </span>
                          </div>
                        </div>
                        <button
                          type="button"
                          onClick={handleexportdata}
                          className="admin_btn"
                        >
                          Export to Excel
                        </button>
                      </div>
                      <div className="d-flex flex-column justify-content-between align-items-start tb-box">
                        <style>
                          {`
                            .datatb-report {
                              overflow: visible !important;
                            }
                            .au-table-scroll {
                              width: 100%;
                              overflow-x: auto;
                              -webkit-overflow-scrolling: touch;
                            }
                            @media (max-width: 768px) {
                              .au-table-scroll .rdt_Table {
                                min-width: 650px;
                              }
                            }
                          `}
                        </style>
                        <div className="au-table-scroll">
                          <DataTable
                            columns={columns}
                            data={filteredRecords}
                            pagination
                            highlightOnHover
                            striped
                            responsive
                            customStyles={customStyles}
                            className="custom-scrollbar custome-icon"
                            noDataComponent={
                              <div className="text-center py-2">
                                <span>No users found</span>
                              </div>
                            }
                          />
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </section>
          </div>
        </div>
      </div>

      <Modal show={show} onHide={handleClose}>
        <Modal.Header closeButton>
          <Modal.Title>Confirm Deletion</Modal.Title>
        </Modal.Header>
        <Modal.Body>
          <p>
            Are you sure you want to delete this record? This action will
            permanently delete all associated data and cannot be undone.
          </p>
        </Modal.Body>
        <Modal.Footer>
          <Button variant="secondary" onClick={handleClose}>
            Cancel
          </Button>
          <Button variant="danger" onClick={handleConfirmDelete}>
            Confirm Delete
          </Button>
        </Modal.Footer>
      </Modal>
    </>
  );
}

export default AdminUsers;